const items = $input.all();
const now = new Date();
const results = [];

// Throttle: max 5 emails per hour, max 20 per day
// We'll check counts later, for now pass through items with rate limit info
for (const item of items) {
    const n = item.json;
    if (!n.id) continue;

    // Build email body
    let html = n.body_html || '';
    if (!html) {
        html = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
            <h2 style="color: #2563eb;">${n.subject || 'Notification'}</h2>
            <p>${n.body_text || 'No details available.'}</p>
            <hr style="border: 1px solid #e5e7eb;">
            <p style="color: #6b7280; font-size: 12px;">Selvi Job Tracker | Application Pipeline Manager</p>
        </div>`;
    } else {
        // Wrap in styled container
        html = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
            ${html}
            <hr style="border: 1px solid #e5e7eb; margin-top: 20px;">
            <p style="color: #6b7280; font-size: 12px;">Selvi Job Tracker | Application Pipeline Manager</p>
        </div>`;
    }

    results.push({ json: {
        ...n,
        email_html: html,
        email_subject: n.subject || `[Selvi Tracker] ${n.notification_type}`
    }});
}

return results.length > 0 ? results : [{ json: { skip: true } }];
